import{_ as e,o as t,c as o,a0 as r}from"./chunks/framework.jwovEGr5.js";const c=JSON.parse('{"title":"녹즙 배달원 강정민","description":"","frontmatter":{},"headers":[],"relativePath":"outta-space/knowledge/books/녹즙-배달원-강정민.md","filePath":"outta-space/knowledge/books/녹즙-배달원-강정민.md"}'),p={name:"outta-space/knowledge/books/녹즙-배달원-강정민.md"};function _(n,a,l,i,s,d){return t(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="녹즙-배달원-강정민" tabindex="-1">녹즙 배달원 강정민 <a class="header-anchor" href="#녹즙-배달원-강정민" aria-label="Permalink to &quot;녹즙 배달원 강정민&quot;">​</a></h1><h2 id="_1-무엇을-다루는가" tabindex="-1">1. 무엇을 다루는가 <a class="header-anchor" href="#_1-무엇을-다루는가" aria-label="Permalink to &quot;1. 무엇을 다루는가&quot;">​</a></h2><p>이 책은 녹즙 배달을 하며 차별과 핍박을 겪는 강정민과, 발랄하지만 다소 클리셰적으로 느껴지는 민주를 중심으로 전개된다.</p><p>작품은 현실적인 문제들을 다루는 듯하지만, 실제로는 주인공에게 지나치게 많은 불행을 몰아넣는 방식으로 이야기를 진행한다. 현실에서 일어날 수 있는 일들을 소재로 삼고 있음에도, 그 배치와 강도가 작위적으로 느껴졌다.</p><h2 id="_2-무엇이-좋았는가" tabindex="-1">2. 무엇이 좋았는가 <a class="header-anchor" href="#_2-무엇이-좋았는가" aria-label="Permalink to &quot;2. 무엇이 좋았는가&quot;">​</a></h2><p>좋았던 점을 굳이 찾자면, 작품이 의도적으로 불쾌감을 만들고 있다면 그 감각 자체는 꽤 선명하게 전달된다는 점이다.</p><p>차별, 핍박, 불행, 답답함 같은 감정을 독자에게 강하게 체험하게 만든다. 이런 찝찝하고 불편한 분위기를 좋아하는 독자라면 오히려 이 점을 장점으로 받아들일 수도 있다.</p><p>또한 중간중간 독자에게 약간의 사이다를 주는 장면이 있어, 계속되는 불행 속에서 최소한의 해소감을 제공하려는 구조는 보인다.</p><h2 id="_3-무엇이-아쉬웠는가" tabindex="-1">3. 무엇이 아쉬웠는가 <a class="header-anchor" href="#_3-무엇이-아쉬웠는가" aria-label="Permalink to &quot;3. 무엇이 아쉬웠는가&quot;">​</a></h2><p>가장 아쉬웠던 점은 불쾌함이 지나치게 작위적으로 느껴졌다는 것이다.</p><p>주인공에게 험난한 일만 계속 일어나고, 인물과 사건이 현실적인 듯하면서도 실제로는 감정적 자극을 위해 배치된 것처럼 보였다. 그 결과 현실 비판이라기보다는 긴 불행 포르노를 보는 느낌에 가까웠다.</p><p>민주의 캐릭터 역시 “발랄한 미친 여자”라는 익숙한 클리셰처럼 느껴졌고, 민주가 가야 하는 나라가 하필 인도라는 점도 지나치게 작위적으로 다가왔다.</p><p>결말에서 잠깐 교훈을 주는 방식도 크게 설득력 있게 느껴지지는 않았다. 긴 불쾌함 끝에 짧은 메시지만 남는 구조라, 감정적으로는 보상보다 피로감이 더 컸다.</p><h2 id="_4-어떤-생각이-남았는가" tabindex="-1">4. 어떤 생각이 남았는가 <a class="header-anchor" href="#_4-어떤-생각이-남았는가" aria-label="Permalink to &quot;4. 어떤 생각이 남았는가&quot;">​</a></h2><p>이 책은 내가 싫어하는 부류의 책이었다.</p><p>현실의 불합리함을 다루는 작품과, 불쾌함을 소비하게 만드는 작품 사이에는 차이가 있다고 느꼈다. 이 책은 나에게 후자에 가까웠다.</p><p>물론 현실은 실제로 불쾌하고 부조리할 수 있다. 그러나 그 불쾌함을 작품 안에 어떻게 배열하느냐에 따라 독자는 “현실을 직면했다”고 느낄 수도 있고, “불행을 억지로 구경했다”고 느낄 수도 있다. 나는 이 책을 후자에 가깝게 받아들였다.</p><h2 id="_5-누구에게-추천할-수-있는가" tabindex="-1">5. 누구에게 추천할 수 있는가 <a class="header-anchor" href="#_5-누구에게-추천할-수-있는가" aria-label="Permalink to &quot;5. 누구에게 추천할 수 있는가&quot;">​</a></h2><p>찝찝하고 불쾌한 분위기의 작품, 인물에게 계속해서 고난이 닥치는 이야기를 좋아하는 사람에게는 추천할 수 있다.</p><p>반대로 현실적인 고통을 다루더라도 어느 정도의 설득력, 절제, 감정적 균형을 원하는 사람에게는 추천하기 어렵다.</p><p>한 줄로 정리하면, 이 책은 현실 비판처럼 보이지만 나에게는 지나치게 작위적인 불행 포르노처럼 느껴진 작품이다.</p>',21)])])}const u=e(p,[["render",_]]);export{c as __pageData,u as default};
